import{_ as t,o,c as n,ae as p}from"./chunks/framework.CFyvOAXl.js";const h=JSON.parse('{"title":"《剑指offer》小结","description":"","frontmatter":{},"headers":[],"relativePath":"program/cpp/CodingInterviewSummary.md","filePath":"program/cpp/CodingInterviewSummary.md","lastUpdated":1610042990000}'),s={name:"program/cpp/CodingInterviewSummary.md"};function e(a,r,g,i,l,d){return o(),n("div",null,[...r[0]||(r[0]=[p('<h1 id="《剑指offer》小结" tabindex="-1">《剑指offer》小结 <a class="header-anchor" href="#《剑指offer》小结" aria-label="Permalink to &quot;《剑指offer》小结&quot;">​</a></h1><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>《剑指offer》这本书适合校招练习算法和数据结构，也可以作为工作后的算法与数据结构巩固练习。</p><p>另外，附上LeetCode上剑指offer（第二版）的在线刷题链接，可在阅读完练习使用：</p><p><a href="https://leetcode-cn.com/problemset/lcof/" target="_blank" rel="noreferrer">https://leetcode-cn.com/problemset/lcof/</a></p><h2 id="正文" tabindex="-1">正文 <a class="header-anchor" href="#正文" aria-label="Permalink to &quot;正文&quot;">​</a></h2><p>这本书的前沿部分已经总结了全书的内容。一共50个算法题，并对这些算法题进行了思路讲解。</p><h3 id="版本" tabindex="-1">版本 <a class="header-anchor" href="#版本" aria-label="Permalink to &quot;版本&quot;">​</a></h3><p>2012年。</p><h3 id="主要内容" tabindex="-1">主要内容 <a class="header-anchor" href="#主要内容" aria-label="Permalink to &quot;主要内容&quot;">​</a></h3><p><strong>第 1 章</strong>介绍流程。</p><p><strong>第 2 章</strong>梳理基础知识。</p><p>第 3 章讨论写出高质量代码的 3 个要点。从规范性、完整性和鲁棒性 3 个方面提高代码的质量。</p><p><strong>第 4 章</strong>总结解决难题的常用思路。用画图、举例和分解复杂问题 3 种思路来解决问题。</p><p><strong>第 5 章</strong>介绍如何优化代码的时间效率和空间效率。学会优化时间效率及空间换时间的常用算法。</p><p><strong>第 6 章</strong>总结各项能力。学习能力和沟通能力、知识迁移能力、抽象建模能力和发散思维能力。</p><p><strong>第 7 章</strong>是两个案例。</p><h3 id="详细" tabindex="-1">详细 <a class="header-anchor" href="#详细" aria-label="Permalink to &quot;详细&quot;">​</a></h3><p><strong>题4替换空格</strong>。测试用例需包含正常情况和异常情况，且考虑时间复杂度。</p><p><strong>题5从尾到头打印链表</strong>。后进先出，使用栈。</p><p><strong>题6重建二叉树</strong>。前序遍历第一个数字为根节点，中序遍历找到根节点位置，从而确定左右子树，再递归解决。</p><p><strong>题8旋转数组的最小数字</strong>。二分法。</p><p><strong>题9斐波那契数列</strong>。递归➕循环。</p><p><strong>题11数值的整数次方</strong>。需考虑底数为0而指数为负数的处理。</p><p><strong>题12打印1到最大的n位数</strong>。大数问题，用字符串模拟加法并打印。</p><p><strong>题13在O(1)时间删除链表节点</strong>。创新；用下一个节点的内容对比被删除的节点，然后把下一个节点删除。</p><p><strong>题14调整属于顺序使偶数位于奇数之前</strong>。双指针。</p><p><strong>题15链表中倒数第k个节点</strong>。双指针遍历。</p><p><strong>题17合并2个排序的链表</strong>。递归。</p><p><strong>题18树的子结构</strong>。递归。</p><p><strong>题19二叉树的镜像</strong>。先序遍历树，递归。</p><p><strong>题21包含min函数的栈</strong>。借用辅助栈保存最小元素。</p><p><strong>题22栈的压入、弹出序列</strong>。举例分析，辅助栈。</p><p><strong>题23从上往下打印二叉树</strong>。队列。</p><p><strong>题24二叉搜索树的后序遍历序列</strong>。找出后序遍历的规律。</p><p><strong>题25二叉树中和为某一值的路径</strong>。栈。</p><p><strong>题26复杂链表的复制</strong>。用O(n)的空间消耗把时间复杂度由O(N^2)降低到O(n)。</p><p><strong>题28字符串的排列</strong>。递归。</p><p><strong>题30最小的k个数</strong>。最大堆。</p><p><strong>题31连续子数组的最大和</strong>。动态规划。</p><p><strong>题35第一个只出现一次的字符</strong>。哈希表。</p><p><strong>题37两个链表的第一个公共节点</strong>。辅助栈。</p><p><strong>题38数字在排序数组中出现的次数</strong>。二分查找、递归。</p><p><strong>题39二叉树的深度</strong>。递归。</p><p><strong>题46求1+2+……+n</strong>。发散思维。</p>',45)])])}const f=t(s,[["render",e]]);export{h as __pageData,f as default};
